    14â†’// #region Disposable Tracking
    15â†’
    16â†’/**
    17â†’ * Enables logging of potentially leaked disposables.
    18â†’ *
    19â†’ * A disposable is considered leaked if it is not disposed or not registered as the child of
    20â†’ * another disposable. This tracking is very simple an only works for classes that either
    21â†’ * extend Disposable or use a DisposableStore. This means there are a lot of false positives.
    22â†’ */
    23â†’const TRACK_DISPOSABLES = false;
    24â†’let disposableTracker: IDisposableTracker | null = null;
    25â†’
    26â†’export interface IDisposableTracker {
    27â†’	/**
    28â†’	 * Is called on construction of a disposable.
    29â†’	*/
    30â†’	trackDisposable(disposable: IDisposable): void;
    31â†’
    32â†’	/**
    33â†’	 * Is called when a disposable is registered as child of another disposable (e.g. {@link DisposableStore}).
    34â†’	 * If parent is `null`, the disposable is removed from its former parent.
    35â†’	*/
    36â†’	setParent(child: IDisposable, parent: IDisposable | null): void;
    37â†’
    38â†’	/**
    39â†’	 * Is called after a disposable is disposed.
    40â†’	*/
    41â†’	markAsDisposed(disposable: IDisposable): void;
    42â†’
    43â†’	/**
    44â†’	 * Indicates that the given object is a singleton which does not need to be disposed.
    45â†’	*/
    46â†’	markAsSingleton(disposable: IDisposable): void;
    47â†’}
    48â†’
    49â†’export class GCBasedDisposableTracker implements IDisposableTracker {
    50â†’
    51â†’	private readonly _registry = new FinalizationRegistry<string>(heldValue => {
    52â†’		console.warn(`[LEAKED DISPOSABLE] ${heldValue}`);
    53â†’	});
    54â†’
    55â†’	trackDisposable(disposable: IDisposable): void {
    56â†’		const stack = new Error('CREATED via:').stack!;
    57â†’		this._registry.register(disposable, stack, disposable);
    58â†’	}
    59â†’
    60â†’	setParent(child: IDisposable, parent: IDisposable | null): void {
    61â†’		if (parent) {
    62â†’			this._registry.unregister(child);
    63â†’		} else {
    64â†’			this.trackDisposable(child);
    65â†’		}
    66â†’	}
    67â†’
    68â†’	markAsDisposed(disposable: IDisposable): void {
    69â†’		this._registry.unregister(disposable);
    70â†’	}
    71â†’
    72â†’	markAsSingleton(disposable: IDisposable): void {
    73â†’		this._registry.unregister(disposable);
    74â†’	}
    75â†’}
    76â†’
    77â†’export interface DisposableInfo {
    78â†’	value: IDisposable;
    79â†’	source: string | null;
    80â†’	parent: IDisposable | null;
    81â†’	isSingleton: boolean;
    82â†’	idx: number;
    83â†’}
    84â†’
    85â†’export class DisposableTracker implements IDisposableTracker {
    86â†’	private static idx = 0;
    87â†’
    88â†’	private readonly livingDisposables = new Map<IDisposable, DisposableInfo>();
    89â†’
    90â†’	private getDisposableData(d: IDisposable): DisposableInfo {
    91â†’		let val = this.livingDisposables.get(d);
    92â†’		if (!val) {
    93â†’			val = { parent: null, source: null, isSingleton: false, value: d, idx: DisposableTracker.idx++ };
    94â†’			this.livingDisposables.set(d, val);
    95â†’		}
    96â†’		return val;
    97â†’	}
    98â†’
    99â†’	trackDisposable(d: IDisposable): void {
   100â†’		const data = this.getDisposableData(d);
   101â†’		if (!data.source) {
   102â†’			data.source =
   103â†’				new Error().stack!;
   104â†’		}
   105â†’	}
   106â†’
   107â†’	setParent(child: IDisposable, parent: IDisposable | null): void {
   108â†’		const data = this.getDisposableData(child);
   109â†’		data.parent = parent;
   110â†’	}
   111â†’
   112â†’	markAsDisposed(x: IDisposable): void {
   113â†’		this.livingDisposables.delete(x);
   114â†’	}
   115â†’
   116â†’	markAsSingleton(disposable: IDisposable): void {
   117â†’		this.getDisposableData(disposable).isSingleton = true;
   118â†’	}
   119â†’
   120â†’	private getRootParent(data: DisposableInfo, cache: Map<DisposableInfo, DisposableInfo>): DisposableInfo {
   121â†’		const cacheValue = cache.get(data);
   122â†’		if (cacheValue) {
   123â†’			return cacheValue;
   124â†’		}
   125â†’
   126â†’		const result = data.parent ? this.getRootParent(this.getDisposableData(data.parent), cache) : data;
   127â†’		cache.set(data, result);
   128â†’		return result;
   129â†’	}
   130â†’
   131â†’	getTrackedDisposables(): IDisposable[] {
   132â†’		const rootParentCache = new Map<DisposableInfo, DisposableInfo>();
   133â†’
   134â†’		const leaking = [...this.livingDisposables.entries()]
   135â†’			.filter(([, v]) => v.source !== null && !this.getRootParent(v, rootParentCache).isSingleton)
   136â†’			.flatMap(([k]) => k);
   137â†’
   138â†’		return leaking;
   139â†’	}
   140â†’
   141â†’	computeLeakingDisposables(maxReported = 10, preComputedLeaks?: DisposableInfo[]): { leaks: DisposableInfo[]; details: string } | undefined {
   142â†’		let uncoveredLeakingObjs: DisposableInfo[] | undefined;
   143â†’		if (preComputedLeaks) {
   144â†’			uncoveredLeakingObjs = preComputedLeaks;
   145â†’		} else {
   146â†’			const rootParentCache = new Map<DisposableInfo, DisposableInfo>();
   147â†’
   148â†’			const leakingObjects = [...this.livingDisposables.values()]
   149â†’				.filter((info) => info.source !== null && !this.getRootParent(info, rootParentCache).isSingleton);
   150â†’
   151â†’			if (leakingObjects.length === 0) {
   152â†’				return;
   153â†’			}
   154â†’			const leakingObjsSet = new Set(leakingObjects.map(o => o.value));
   155â†’
   156â†’			// Remove all objects that are a child of other leaking objects. Assumes there are no cycles.
   157â†’			uncoveredLeakingObjs = leakingObjects.filter(l => {
   158â†’				return !(l.parent && leakingObjsSet.has(l.parent));
   159â†’			});
   160â†’
   161â†’			if (uncoveredLeakingObjs.length === 0) {
   162â†’				throw new Error('There are cyclic diposable chains!');
   163â†’			}
   164â†’		}
   165â†’
   166â†’		if (!uncoveredLeakingObjs) {
   167â†’			return undefined;
   168â†’		}
   169â†’
   170â†’		function getStackTracePath(leaking: DisposableInfo): string[] {
   171â†’			function removePrefix(array: string[], linesToRemove: (string | RegExp)[]) {
   172â†’				while (array.length > 0 && linesToRemove.some(regexp => typeof regexp === 'string' ? regexp === array[0] : array[0].match(regexp))) {
   173â†’					array.shift();
   174â†’				}
   175â†’			}
   176â†’
   177â†’			const lines = leaking.source!.split('\n').map(p => p.trim().replace('at ', '')).filter(l => l !== '');
   178â†’			removePrefix(lines, ['Error', /^trackDisposable \(.*\)$/, /^DisposableTracker.trackDisposable \(.*\)$/]);
   179â†’			return lines.reverse();
   180â†’		}
   181â†’
   182â†’		const stackTraceStarts = new SetMap<string, DisposableInfo>();
   183â†’		for (const leaking of uncoveredLeakingObjs) {
   184â†’			const stackTracePath = getStackTracePath(leaking);
   185â†’			for (let i = 0; i <= stackTracePath.length; i++) {
   186â†’				stackTraceStarts.add(stackTracePath.slice(0, i).join('\n'), leaking);
   187â†’			}
   188â†’		}
   189â†’
   190â†’		// Put earlier leaks first
   191â†’		uncoveredLeakingObjs.sort(compareBy(l => l.idx, numberComparator));
   192â†’
   193â†’		let message = '';
   194â†’
   195â†’		let i = 0;
   196â†’		for (const leaking of uncoveredLeakingObjs.slice(0, maxReported)) {
   197â†’			i++;
   198â†’			const stackTracePath = getStackTracePath(leaking);
   199â†’			const stackTraceFormattedLines = [];
   200â†’
   201â†’			for (let i = 0; i < stackTracePath.length; i++) {
   202â†’				let line = stackTracePath[i];
   203â†’				const starts = stackTraceStarts.get(stackTracePath.slice(0, i + 1).join('\n'));
   204â†’				line = `(shared with ${starts.size}/${uncoveredLeakingObjs.length} leaks) at ${line}`;
   205â†’
   206â†’				const prevStarts = stackTraceStarts.get(stackTracePath.slice(0, i).join('\n'));
   207â†’				const continuations = groupBy([...prevStarts].map(d => getStackTracePath(d)[i]), v => v);
   208â†’				delete continuations[stackTracePath[i]];
   209â†’				for (const [cont, set] of Object.entries(continuations)) {
   210â†’					if (set) {
   211â†’						stackTraceFormattedLines.unshift(`    - stacktraces of ${set.length} other leaks continue with ${cont}`);
   212â†’					}
   213â†’				}
   214â†’
   215â†’				stackTraceFormattedLines.unshift(line);
   216â†’			}
   217â†’
   218â†’			message += `\n\n\n==================== Leaking disposable ${i}/${uncoveredLeakingObjs.length}: ${leaking.value.constructor.name} ====================\n${stackTraceFormattedLines.join('\n')}\n============================================================\n\n`;
   219â†’		}
   220â†’
   221â†’		if (uncoveredLeakingObjs.length > maxReported) {
   222â†’			message += `\n\n\n... and ${uncoveredLeakingObjs.length - maxReported} more leaking disposables\n\n`;
   223â†’		}
   224â†’
   225â†’		return { leaks: uncoveredLeakingObjs, details: message };
   226â†’	}
   227â†’}
   228â†’
   229â†’export function setDisposableTracker(tracker: IDisposableTracker | null): void {
   230â†’	disposableTracker = tracker;
   231â†’}
   232â†’
   233â†’if (TRACK_DISPOSABLES) {
   234â†’	const __is_disposable_tracked__ = '__is_disposable_tracked__';
   235â†’	setDisposableTracker(new class implements IDisposableTracker {
   236â†’		trackDisposable(x: IDisposable): void {
   237â†’			const stack = new Error('Potentially leaked disposable').stack!;
   238â†’			setTimeout(() => {
   239â†’				// eslint-disable-next-line local/code-no-any-casts
   240â†’				if (!(x as any)[__is_disposable_tracked__]) {
   241â†’					console.log(stack);
   242â†’				}
   243â†’			}, 3000);
   244â†’		}
   245â†’
   246â†’		setParent(child: IDisposable, parent: IDisposable | null): void {
   247â†’			if (child && child !== Disposable.None) {
   248â†’				try {
   249â†’					// eslint-disable-next-line local/code-no-any-casts
   250â†’					(child as any)[__is_disposable_tracked__] = true;
   251â†’				} catch {
   252â†’					// noop
   253â†’				}
   254â†’			}
   255â†’		}
   256â†’
   257â†’		markAsDisposed(disposable: IDisposable): void {
   258â†’			if (disposable && disposable !== Disposable.None) {
   259â†’				try {
   260â†’					// eslint-disable-next-line local/code-no-any-casts
   261â†’					(disposable as any)[__is_disposable_tracked__] = true;
   262â†’				} catch {
   263â†’					// noop
   264â†’				}
   265â†’			}
   266â†’		}
   267â†’		markAsSingleton(disposable: IDisposable): void { }
   268â†’	});
   269â†’}
   270â†’
   271â†’export function trackDisposable<T extends IDisposable>(x: T): T {
   272â†’	disposableTracker?.trackDisposable(x);
   273â†’	return x;
   274â†’}
   275â†’
   276â†’export function markAsDisposed(disposable: IDisposable): void {
   277â†’	disposableTracker?.markAsDisposed(disposable);
   278â†’}
   279â†’
   280â†’function setParentOfDisposable(child: IDisposable, parent: IDisposable | null): void {
   281â†’	disposableTracker?.setParent(child, parent);
   282â†’}
   283â†’
   284â†’function setParentOfDisposables(children: IDisposable[], parent: IDisposable | null): void {
   285â†’	if (!disposableTracker) {
   286â†’		return;
   287â†’	}
   288â†’	for (const child of children) {
   289â†’		disposableTracker.setParent(child, parent);
   290â†’	}
   291â†’}
   292â†’
   293â†’/**
   294â†’ * Indicates that the given object is a singleton which does not need to be disposed.
   295â†’*/
   296â†’export function markAsSingleton<T extends IDisposable>(singleton: T): T {
   297â†’	disposableTracker?.markAsSingleton(singleton);
   298â†’	return singleton;
   299â†’}
   300â†’
   301â†’// #endregion
   302â†’
   303â†’/**
   304â†’ * An object that performs a cleanup operation when `.dispose()` is called.
   305â†’ *
   306â†’ * Some examples of how disposables are used:
   307â†’ *
   308â†’ * - An event listener that removes itself when `.dispose()` is called.
   309â†’ * - A resource such as a file system watcher that cleans up the resource when `.dispose()` is called.
   310â†’ * - The return value from registering a provider. When `.dispose()` is called, the provider is unregistered.
   311â†’ */
   312â†’export interface IDisposable {
   313â†’	dispose(): void;
   314â†’}
   315â†’
   316â†’/**
   317â†’ * Check if `thing` is {@link IDisposable disposable}.
   318â†’ */
   319â†’export function isDisposable<E>(thing: E): thing is E & IDisposable {
   320â†’	// eslint-disable-next-line local/code-no-any-casts
   321â†’	return typeof thing === 'object' && thing !== null && typeof (<IDisposable><any>thing).dispose === 'function' && (<IDisposable><any>thing).dispose.length === 0;
   322â†’}
   323â†’
   324â†’/**
   325â†’ * Disposes of the value(s) passed in.
   326â†’ */
   327â†’export function dispose<T extends IDisposable>(disposable: T): T;
   328â†’export function dispose<T extends IDisposable>(disposable: T | undefined): T | undefined;
   329â†’export function dispose<T extends IDisposable, A extends Iterable<T> = Iterable<T>>(disposables: A): A;
   330â†’export function dispose<T extends IDisposable>(disposables: Array<T>): Array<T>;
   331â†’export function dispose<T extends IDisposable>(disposables: ReadonlyArray<T>): ReadonlyArray<T>;
   332â†’export function dispose<T extends IDisposable>(arg: T | Iterable<T> | undefined): any {
   333â†’	if (Iterable.is(arg)) {
   334â†’		const errors: any[] = [];
   335â†’
   336â†’		for (const d of arg) {
   337â†’			if (d) {
   338â†’				try {
   339â†’					d.dispose();
   340â†’				} catch (e) {
   341â†’					errors.push(e);
   342â†’				}
   343â†’			}
   344â†’		}
   345â†’
   346â†’		if (errors.length === 1) {
   347â†’			throw errors[0];
   348â†’		} else if (errors.length > 1) {
   349â†’			throw new AggregateError(errors, 'Encountered errors while disposing of store');
   350â†’		}
   351â†’
   352â†’		return Array.isArray(arg) ? [] : arg;
   353â†’	} else if (arg) {
   354â†’		arg.dispose();
   355â†’		return arg;
   356â†’	}
   357â†’}
   358â†’
   359â†’export function disposeIfDisposable<T extends IDisposable | object>(disposables: Array<T>): Array<T> {
   360â†’	for (const d of disposables) {
   361â†’		if (isDisposable(d)) {
   362â†’			d.dispose();
   363â†’		}
   364â†’	}
   365â†’	return [];
   366â†’}
   367â†’
   368â†’/**
   369â†’ * Combine multiple disposable values into a single {@link IDisposable}.
   370â†’ */
   371â†’export function combinedDisposable(...disposables: IDisposable[]): IDisposable {
   372â†’	const parent = toDisposable(() => dispose(disposables));
   373â†’	setParentOfDisposables(disposables, parent);
   374â†’	return parent;
   375â†’}
   376â†’
   377â†’class FunctionDisposable implements IDisposable {
   378â†’	private _isDisposed: boolean;
   379â†’	private readonly _fn: () => void;
   380â†’
   381â†’	constructor(fn: () => void) {
   382â†’		this._isDisposed = false;
   383â†’		this._fn = fn;
   384â†’		trackDisposable(this);
   385â†’	}
   386â†’
   387â†’	dispose() {
   388â†’		if (this._isDisposed) {
   389â†’			return;
   390â†’		}
   391â†’		if (!this._fn) {
   392â†’			throw new Error(`Unbound disposable context: Need to use an arrow function to preserve the value of this`);
   393â†’		}
   394â†’		this._isDisposed = true;
   395â†’		markAsDisposed(this);
   396â†’		this._fn();
   397â†’	}
   398â†’}
   399â†’
   400â†’/**
   401â†’ * Turn a function that implements dispose into an {@link IDisposable}.
   402â†’ *
   403â†’ * @param fn Clean up function, guaranteed to be called only **once**.
   404â†’ */
   405â†’export function toDisposable(fn: () => void): IDisposable {
   406â†’	return new FunctionDisposable(fn);
   407â†’}
   408â†’
   409â†’/**
   410â†’ * Manages a collection of disposable values.
   411â†’ *
   412â†’ * This is the preferred way to manage multiple disposables. A `DisposableStore` is safer to work with than an
   413â†’ * `IDisposable[]` as it considers edge cases, such as registering the same value multiple times or adding an item to a
   414â†’ * store that has already been disposed of.
   415â†’ */
   416â†’export class DisposableStore implements IDisposable {
   417â†’
   418â†’	static DISABLE_DISPOSED_WARNING = false;
   419â†’
   420â†’	private readonly _toDispose = new Set<IDisposable>();
   421â†’	private _isDisposed = false;
   422â†’
   423â†’	constructor() {
   424â†’		trackDisposable(this);
   425â†’	}
   426â†’
   427â†’	/**
   428â†’	 * Dispose of all registered disposables and mark this object as disposed.
   429â†’	 *
   430â†’	 * Any future disposables added to this object will be disposed of on `add`.
   431â†’	 */
   432â†’	public dispose(): void {
   433â†’		if (this._isDisposed) {
   434â†’			return;
   435â†’		}
   436â†’
   437â†’		markAsDisposed(this);
   438â†’		this._isDisposed = true;
   439â†’		this.clear();
   440â†’	}
   441â†’
   442â†’	/**
   443â†’	 * @return `true` if this object has been disposed of.
   444â†’	 */
   445â†’	public get isDisposed(): boolean {
   446â†’		return this._isDisposed;
   447â†’	}
   448â†’
   449â†’	/**
   450â†’	 * Dispose of all registered disposables but do not mark this object as disposed.
   451â†’	 */
   452â†’	public clear(): void {
   453â†’		if (this._toDispose.size === 0) {
   454â†’			return;
   455â†’		}
   456â†’
   457â†’		try {
   458â†’			dispose(this._toDispose);
   459â†’		} finally {
   460â†’			this._toDispose.clear();
   461â†’		}
   462â†’	}
   463â†’
   464â†’	/**
   465â†’	 * Add a new {@link IDisposable disposable} to the collection.
   466â†’	 */
   467â†’	public add<T extends IDisposable>(o: T): T {
   468â†’		if (!o || o === Disposable.None) {
   469â†’			return o;
   470â†’		}
   471â†’		if ((o as unknown as DisposableStore) === this) {
   472â†’			throw new Error('Cannot register a disposable on itself!');
   473â†’		}
   474â†’
   475â†’		setParentOfDisposable(o, this);
   476â†’		if (this._isDisposed) {
   477â†’			if (!DisposableStore.DISABLE_DISPOSED_WARNING) {
   478â†’				console.warn(new Error('Trying to add a disposable to a DisposableStore that has already been disposed of. The added object will be leaked!').stack);
   479â†’			}
   480â†’		} else {
   481â†’			this._toDispose.add(o);
   482â†’		}
   483â†’
   484â†’		return o;
   485â†’	}
   486â†’
   487â†’	/**
   488â†’	 * Deletes a disposable from store and disposes of it. This will not throw or warn and proceed to dispose the
   489â†’	 * disposable even when the disposable is not part in the store.
   490â†’	 */
   491â†’	public delete<T extends IDisposable>(o: T): void {
   492â†’		if (!o) {
   493â†’			return;
   494â†’		}
   495â†’		if ((o as unknown as DisposableStore) === this) {
   496â†’			throw new Error('Cannot dispose a disposable on itself!');
   497â†’		}
   498â†’		this._toDispose.delete(o);
   499â†’		o.dispose();
   500â†’	}
   501â†’
   502â†’	/**
   503â†’	 * Deletes the value from the store, but does not dispose it.
   504â†’	 */
   505â†’	public deleteAndLeak<T extends IDisposable>(o: T): void {
   506â†’		if (!o) {
   507â†’			return;
   508â†’		}
   509â†’		if (this._toDispose.delete(o)) {
   510â†’			setParentOfDisposable(o, null);
   511â†’		}
   512â†’	}
   513â†’
   514â†’	public assertNotDisposed(): void {
   515â†’		if (this._isDisposed) {
   516â†’			onUnexpectedError(new BugIndicatingError('Object disposed'));
   517â†’		}
   518â†’	}
   519â†’}
